// 判斷 AI 傳入的參數類型並決定處理方式
const input = $input.item.json;

// 台灣主要城市座標對照表
const taiwanCities = {
  '台北': { lat: 25.0330, lon: 121.5654 },
  '新北': { lat: 25.0122, lon: 121.4654 },
  '桃園': { lat: 24.9936, lon: 121.3010 },
  '台中': { lat: 24.1477, lon: 120.6736 },
  '台南': { lat: 22.9997, lon: 120.2270 },
  '高雄': { lat: 22.6273, lon: 120.3014 },
  '基隆': { lat: 25.1276, lon: 121.7392 },
  '新竹': { lat: 24.8138, lon: 120.9675 },
  '嘉義': { lat: 23.4800, lon: 120.4491 },
  '宜蘭': { lat: 24.7021, lon: 121.7378 },
  '花蓮': { lat: 23.9871, lon: 121.6015 },
  '台東': { lat: 22.7583, lon: 121.1444 }
};

let result = {
  needGeocoding: false,
  lat: null,
  lon: null,
  locationName: '',
  originalLocation: '',
  exclude: input.exclude || 'minutely,alerts'
};

// 情況 1: AI 直接提供經緯度
if (input.lat && input.lon) {
  result.needGeocoding = false;
  result.lat = parseFloat(input.lat);
  result.lon = parseFloat(input.lon);
  result.locationName = input.locationName || '指定位置';
  result.originalLocation = input.locationName || `${result.lat}, ${result.lon}`;
}
// 情況 2: AI 提供城市名稱
else if (input.city || input.location) {
  const cityInput = input.city || input.location;
  result.originalLocation = cityInput;

  // 檢查是否為台灣預設城市
  if (taiwanCities[cityInput]) {
    result.needGeocoding = false;
    result.lat = taiwanCities[cityInput].lat;
    result.lon = taiwanCities[cityInput].lon;
    result.locationName = cityInput;
  } else {
    // 需要 geocoding
    result.needGeocoding = true;
    result.locationName = cityInput;
  }
}
// 情況 3: 沒有提供任何參數，預設台北
else {
  result.needGeocoding = false;
  result.lat = 25.0330;
  result.lon = 121.5654;
  result.locationName = '台北';
  result.originalLocation = '台北';
}

return { json: result };

// 解析 geocoding 結果
const geocodeResult = $input.item.json;
const parseInput = $('Parse Input').item.json;

if (!geocodeResult || geocodeResult.length === 0) {
  throw new Error(`找不到地點：${parseInput.locationName}`);
}

const location = geocodeResult[0];

return {
  json: {
    lat: location.lat,
    lon: location.lon,
    locationName: location.local_names?.zh || location.name || parseInput.locationName,
    originalLocation: parseInput.originalLocation,
    exclude: parseInput.exclude
  }
};

// 格式化天氣資料為繁體中文回應
const weatherData = $input.item.json;
const locationInfo = $('Merge').item.json;
const cityName = locationInfo.locationName;

// 天氣狀況中文對照
const weatherDesc = {
  'Clear': '晴朗',
  'Clouds': '多雲',
  'Rain': '雨',
  'Drizzle': '毛毛雨',
  'Thunderstorm': '雷雨',
  'Snow': '雪',
  'Mist': '薄霧',
  'Fog': '霧',
  'Haze': '霾'
};

if (!weatherData.current) {
  return { 
    json: { 
      output: `無法取得 ${cityName} 的天氣資料，請稍後再試。` 
    } 
  };
}

const current = weatherData.current;
const temp = Math.round(current.temp);
const feelsLike = Math.round(current.feels_like);
const humidity = current.humidity;
const windSpeed = (current.wind_speed * 3.6).toFixed(1); // 轉換為 km/h
const weather = current.weather[0];
const mainWeather = weatherDesc[weather.main] || weather.main;
const uvIndex = current.uvi;

// 建立基本回應
let response = `📍 ${cityName} 目前天氣\n\n`;
response += `🌡️ 溫度：${temp}°C（體感 ${feelsLike}°C）\n`;
response += `☁️ 天氣：${mainWeather}\n`;
response += `💧 濕度：${humidity}%\n`;
response += `💨 風速：${windSpeed} km/h\n`;
response += `☀️ 紫外線指數：${uvIndex}\n`;

// 降雨機率（如果有）
if (current.pop) {
  response += `🌧️ 降雨機率：${Math.round(current.pop * 100)}%\n`;
}

// 未來幾小時預報
if (weatherData.hourly && weatherData.hourly.length > 0) {
  response += `\n⏰ 未來幾小時：\n`;
  for (let i = 1; i <= 3 && i < weatherData.hourly.length; i++) {
    const hour = weatherData.hourly[i];
    const time = new Date(hour.dt * 1000);
    const hourTemp = Math.round(hour.temp);
    const hourWeather = weatherDesc[hour.weather[0].main] || hour.weather[0].main;
    const hourPop = hour.pop ? ` (降雨 ${Math.round(hour.pop * 100)}%)` : '';
    response += `  ${time.getHours()}:00 - ${hourTemp}°C ${hourWeather}${hourPop}\n`;
  }
}

// 未來幾天預報
if (weatherData.daily && weatherData.daily.length > 1) {
  response += `\n📅 未來幾天：\n`;
  for (let i = 1; i <= 3 && i < weatherData.daily.length; i++) {
    const day = weatherData.daily[i];
    const date = new Date(day.dt * 1000);
    const minTemp = Math.round(day.temp.min);
    const maxTemp = Math.round(day.temp.max);
    const dayWeather = weatherDesc[day.weather[0].main] || day.weather[0].main;
    const dayPop = day.pop ? ` (降雨 ${Math.round(day.pop * 100)}%)` : '';
    response += `  ${date.getMonth()+1}/${date.getDate()} - ${minTemp}~${maxTemp}°C ${dayWeather}${dayPop}\n`;
  }
}

return { json: { output: response } };
